function buildDynamicPanchang(dateKey, locationKey){
  const date=new Date(dateKey+"T12:00:00");
  const dow=date.getDay();
  const month=date.getMonth();
  const moon=getMoonPhase(date);
  const isIndia=getLocationMeta(locationKey).tz==="Asia/Kolkata"||getLocationMeta(locationKey).region==="India";

  // Tithi from moon phase
  const TITHIS=["Amavasya","Pratipada","Dwitiya","Tritiya","Chaturthi","Panchami","Shashthi","Saptami","Ashtami","Navami","Dashami","Ekadashi","Dwadashi","Trayodashi","Chaturdashi","Purnima"];
  const TITHI_DEITIES=["Pitru","Brahma","Vidhatr","Vishnu","Ganesha","Naga","Kartikeya","Shiva","Durga","Rama","Yama","Vishnu","Yama","Shiva","Shiva","Vishnu"];
  // pct 0=new moon, 0.5=full moon. Convert to 0-29 tithi index
  let lunarDay=Math.round(moon.pct*29.5);
  if(lunarDay>=15){lunarDay=29-lunarDay;}
  lunarDay=Math.max(0,Math.min(15,lunarDay));
  const paksha=moon.pct<0.01||moon.pct>0.98?"Krishnapaksha":moon.pct<=0.5?"Shukla Paksha":"Krishna Paksha";
  const tithiName=TITHIS[lunarDay]||"Panchami";
  const tithiDeity=TITHI_DEITIES[lunarDay]||"Vishnu";

  // Hindu months
  const hinduMonths=["Magha","Phalguna","Chaitra","Vaishakha","Jyeshtha","Ashadha","Shravana","Bhadrapada","Ashwin","Kartik","Margashirsha","Paush"];
  const hinduMonth=hinduMonths[month]||"Chaitra";

  // Nakshatra — approximate rotation (27 nakshatras per lunar month ~= 1/day)
  const NAKSHATRAS=["Ashwini","Bharani","Krittika","Rohini","Mrigashira","Ardra","Punarvasu","Pushya","Ashlesha","Magha","Purva Phalguni","Uttara Phalguni","Hasta","Chitra","Swati","Vishakha","Anuradha","Jyeshtha","Mula","Purva Ashadha","Uttara Ashadha","Shravana","Dhanishtha","Shatabhisha","Purva Bhadrapada","Uttara Bhadrapada","Revati"];
  const refDays=Math.round((date-new Date("2026-01-01T00:00:00Z"))/(86400000));
  const nakshatraName=NAKSHATRAS[((refDays%27)+27)%27];

  // Weekday data
  const WDAY_DATA=[
    {name:"Ravivara",ruler:"Surya (Sun)",color:"#FF8C00",lucky:"Red & Saffron",num:"1"},
    {name:"Somvara",ruler:"Chandra (Moon)",color:"#AAAAFF",lucky:"White & Silver",num:"2"},
    {name:"Mangalavara",ruler:"Mangal (Mars)",color:"#DC143C",lucky:"Red",num:"9"},
    {name:"Budhavara",ruler:"Budha (Mercury)",color:"#3DDC84",lucky:"Green",num:"5"},
    {name:"Guruvara",ruler:"Guru (Jupiter)",color:"#FFD700",lucky:"Yellow & Gold",num:"3"},
    {name:"Shukravara",ruler:"Shukra (Venus)",color:"#F02890",lucky:"White & Pink",num:"6"},
    {name:"Shanivara",ruler:"Shani (Saturn)",color:"#8855FF",lucky:"Black & Blue",num:"8"},
  ];
  const wd=WDAY_DATA[dow];

  // Sunrise/sunset approximate (month-based)
  const sunriseIST=["6:54 AM","6:43 AM","6:28 AM","6:05 AM","5:46 AM","5:36 AM","5:41 AM","5:51 AM","5:56 AM","6:04 AM","6:17 AM","6:42 AM"];
  const sunsetIST=["5:56 PM","6:16 PM","6:36 PM","6:56 PM","7:11 PM","7:21 PM","7:16 PM","7:01 PM","6:41 PM","6:02 PM","5:31 PM","5:41 PM"];
  const sunriseUSA=["7:25 AM","7:00 AM","7:30 AM","7:00 AM","6:35 AM","6:15 AM","6:20 AM","6:40 AM","7:00 AM","7:20 AM","7:40 AM","7:50 AM"];
  const sunsetUSA=["5:30 PM","5:55 PM","7:15 PM","7:35 PM","7:55 PM","8:15 PM","8:10 PM","7:50 PM","7:15 PM","6:40 PM","5:25 PM","5:15 PM"];
  const sr=isIndia?sunriseIST[month]:sunriseUSA[month];
  const ss=isIndia?sunsetIST[month]:sunsetUSA[month];

  // Rahu Kaal by weekday (approximate start times from sunrise)
  const rahuKaalByDay=isIndia
    ?["4:30-6:00 PM","7:30-9:00 AM","3:00-4:30 PM","12:00-1:30 PM","1:30-3:00 PM","10:30 AM-12:00 PM","9:00-10:30 AM"]
    :["3:30-5:00 PM","8:00-9:30 AM","3:00-4:30 PM","12:00-1:30 PM","1:30-3:00 PM","10:30 AM-12:00 PM","9:00-10:30 AM"];
  const rahuKaal=rahuKaalByDay[dow];

  const dateStr=date.toLocaleDateString("en-US",{weekday:"long",year:"numeric",month:"long",day:"numeric"});
  return {
    gregorian:dateStr,
    hindu:`${hinduMonth} ${paksha.split(" ")[0]} ${tithiName}, VS 2082`,
    samvat:"Vikram Samvat 2082",
    masa:`${hinduMonth} (Approx.)`,
    paksha,
    tithi:{name:tithiName,number:lunarDay,ends:"Varies",quality:"Auspicious",deity:tithiDeity},
    nakshatra:{name:nakshatraName,ends:"Varies",quality:"Sacred",deity:wd.ruler,pada:"1st"},
    yoga:{name:"Saubhagya",ends:"End of day"},
    karana:{morning:"Bava",evening:"Balava"},
    sunrise:sr,sunset:ss,moonrise:"Varies",moonset:"Varies",
    abhijit:"11:30 AM-12:18 PM",
    amritKaal:"Varies",
    brahmaMuhurat:"4:30-6:00 AM",
    rahuKaal,gulikaKaal:"Varies",yamaganda:"Varies",
    weekday:wd.name,weekdayColor:wd.color,weekdayGem:"Varies",
    moonPhase:moon.name,moonPct:Math.round(moon.pct*100),
    rashi:"Mithuna (Gemini)",rashiLord:"Mercury",
    weekdayRuler:wd.ruler,luckyColor:wd.lucky,luckyNumber:wd.num,
    todayObservances:[tithiName+" — "+paksha],
    locationMode:isIndia?"india":"global",
    isDynamic:true,
  };
}

function getLocationPanchang(dateKey, locationKey) {
  const dayMap = LOCATION_PANCHANG[dateKey] || {};
  if (dayMap[locationKey]) return dayMap[locationKey];
  if (dateKey === "2026-03-26" && getLocationMeta(locationKey).region === "India") return INDIA_RAM_NAVAMI;
  if (dateKey === "2026-03-25" && getLocationMeta(locationKey).region === "India") return INDIA_PANCHANG;
  if (dateKey === "2026-03-25") return PANCHANG;
  if (dayMap.austin) return dayMap.austin; // fallback to any city on same date
  // Dynamic fallback for all other dates — computed from moon phase
  return buildDynamicPanchang(dateKey, locationKey);
}

function getLocationMeta(locationKey){
  return LOCATION_OPTIONS.find(x=>x.key===locationKey) || LOCATION_OPTIONS[0];
}


function getTodayObservances(locationKey){
  const localDateKey=getLocalDateKeyForLocation(locationKey);
  const local=getLocationPanchang(localDateKey, locationKey);
  return Array.isArray(local.todayObservances) && local.todayObservances.length
    ? local.todayObservances
    : [local.nextFestival || "Rama Navami — Mar 26"];
}

function formatLocationToday(locationKey){
  const localDateKey=getLocalDateKeyForLocation(locationKey);
  const local=getLocationPanchang(localDateKey, locationKey);
  const meta=getLocationMeta(locationKey);
  const observances=getTodayObservances(locationKey);
  const nextLine = local.nextFestival ? `
**Next major festival:** ${local.nextFestival}` : "";
  return `**📍 Today in ${meta.label}**

**Vedic date:** ${local.hindu}
**Tithi:** ${local.tithi.name} (ends ${local.tithi.ends})
**Nakshatra:** ${local.nakshatra.name}
**Yoga:** ${local.yoga.name}
**Karana:** ${local.karana.morning}${local.karana.evening ? ` → ${local.karana.evening}` : ""}

**Today's observances:** ${observances.join(" · ")}
**Best windows:** Prayer ${local.brahmaMuhurat} · Travel outside Rahu Kaal ${local.rahuKaal}${nextLine}`;
}

