/* ── Live days recalculation (SACRED_DATES) — runs after declaration ── */
(function(){
  const _now=new Date();
  const _today=new Date(_now.getFullYear(),_now.getMonth(),_now.getDate());
  const _yr=_now.getFullYear();
  const _MA={Jan:0,Feb:1,Mar:2,Apr:3,May:4,Jun:5,Jul:6,Aug:7,Sep:8,Oct:9,Nov:10,Dec:11};
  SACRED_DATES.forEach(sd=>{
    const p=(sd.date||"").split(" ");
    if(p.length===2){const m=_MA[p[0]],dy=parseInt(p[1]);
      if(m!==undefined&&!isNaN(dy)){let d=new Date(_yr,m,dy);
        if(d<_today)d=new Date(_yr+1,m,dy);
        sd.days=Math.round((d-_today)/(864e5));}}
  });
})();

