/* ── Fuzzy bigram match — handles typos & misspellings ── */
function _fuzzy(needle,haystack){
  needle=needle.toLowerCase(); haystack=haystack.toLowerCase();
  if(haystack.includes(needle)) return true;
  if(needle.length<3) return false;
  // Build bigrams of needle, check how many appear in haystack
  let matched=0,total=0;
  for(let i=0;i<needle.length-1;i++){
    const g=needle.slice(i,i+2);
    total++;
    if(haystack.includes(g)) matched++;
  }
  return total>0&&matched/total>=0.5;
}
/* ── Hindu tithi aliases so "ashtami" / "ashthami" etc. all resolve ── */
const TITHI_ALIASES={
  "pratipada":["first","1st","pratipad"],"dwitiya":["second","2nd","dvitiya"],"tritiya":["third","3rd"],
  "chaturthi":["fourth","4th","chaturti","chathurthi","sankashti","ganesh chaturthi"],
  "panchami":["fifth","5th","vasant panchami","naga panchami"],"shashthi":["sixth","6th","shashti","skanda shashti"],
  "saptami":["seventh","7th","ratha saptami"],"ashtami":["eighth","8th","ashthami","asthami","janmashtami","radha ashtami","krishna ashtami","durga ashtami","maha ashtami","kalashtami"],
  "navami":["ninth","9th","naomi","navmi","ram navami","shri ram navami","durgashtami"],"dashami":["tenth","10th","vijaya dashami","dussehara"],
  "ekadashi":["eleventh","11th","ekadasi","ekadashi","hari din"],"dwadashi":["twelfth","12th"],"trayodashi":["thirteenth","13th","pradosh"],
  "chaturdashi":["fourteenth","14th","shivratri","maha shivratri","masik shivratri"],"purnima":["full moon","poornima","poornami","purnami","full moonday"],
  "amavasya":["new moon","no moon","amavas","amavaasya","amawasya"]
};

function globalSearch(query) {
  if (!query.trim()) return [];
  const q = query.toLowerCase().trim();
  /* Expand query via tithi aliases */
  let expandedTerms=[q];
  Object.entries(TITHI_ALIASES).forEach(([tithi,aliases])=>{
    if(q.includes(tithi)||aliases.some(a=>q.includes(a))){
      expandedTerms=[q,tithi,...aliases];
    }
  });
  /* Split into meaningful words (length > 2) for multi-word matching */
  const words = q.split(/\s+/).filter(w=>w.length>2);
  const results = [];
  const seen = new Set();
  const add = (type, item, score) => {
    const key = type+":"+(item.id||item.name);
    if (!seen.has(key)) { seen.add(key); results.push({type,item,score}); }
    else {
      const existing = results.find(r=>r.type===type&&(r.item.id||r.item.name)===(item.id||item.name));
      if(existing && score > existing.score) existing.score = score;
    }
  };
  /* Score helper: check exact phrase, word-level, AND fuzzy */
  const score = (fields, exactBonus=0) => {
    const text = fields.join(" ").toLowerCase();
    let best = 0;
    /* Check all expanded terms */
    for(const term of expandedTerms){
      if(text.startsWith(term)) best=Math.max(best,12+exactBonus);
      else if(text.includes(term)) best=Math.max(best,8+exactBonus);
    }
    /* Word-level exact */
    if(words.length>1){
      const matchCount = words.filter(w=>text.includes(w)).length;
      if(matchCount===words.length) best=Math.max(best,7+exactBonus);
      else if(matchCount>0) best=Math.max(best,2*matchCount);
    } else if(words.length===1){
      if(text.includes(words[0])) best=Math.max(best,5);
    }
    /* Fuzzy fallback for typos — only if no exact match found */
    if(best===0&&q.length>=3){
      const allTerms=[q,...words];
      for(const t of allTerms){
        const fieldWords=text.split(/\s+/);
        if(fieldWords.some(fw=>_fuzzy(t,fw))) best=Math.max(best,3);
      }
    }
    return best;
  };
  FESTIVALS.forEach(f => {
    const s=score([f.name],4)+score([f.desc,f.vedic||"",f.region||"",f.howTo||""]);
    if(s>0) add("festival",f,s);
  });
  MANTRAS.forEach(m => {
    const s=score([m.name,m.deity],4)+score([m.meaning||"",m.benefits||"",m.cat||"",m.sanskrit||""]);
    if(s>0) add("mantra",m,s);
  });
  SACRED_DATES.forEach(sd => {
    const s=score([sd.name],2)+score([sd.desc||""]);
    if(s>0) add("sacred",sd,s);
  });
  RITUALS.forEach(r => {
    const s=score([r.name,r.deity||""],4)+score([r.benefits||"",r.subtitle||"",r.difficulty||""]);
    if(s>0) add("ritual",r,s);
  });
  MUHURAT_DATA.forEach(m => {
    const s=score([m.name],2)+score([m.desc||"",m.bestTime||""]);
    if(s>0) add("muhurat",m,s);
  });
  return results.sort((a,b)=>b.score-a.score).slice(0,40);
}

/* ══════════════════════════════════════════════════════
   SPEECH SYNTHESIS — Language-Aware Indian Voice Engine
   Mantra text selection by language:
     Hindi / Sanskrit / Marathi → Devanagari  (hi-IN / mr-IN)
     Tamil                      → Romanised    (ta-IN)
     Telugu                     → Romanised    (te-IN)
     English (default)          → Devanagari  (hi-IN)
   Voice preference per locale (best → fallback):
     hi-IN: Google हिन्दी > Lekha > Heera > Ravi > any hi-IN
     mr-IN: Google मराठी  > any mr-IN  → fallback hi-IN
     ta-IN: Google தமிழ்  > any ta-IN
     te-IN: Google తెలుగు > any te-IN
     en-IN: Rishi > Veena > Google en-IN > any en-IN
══════════════════════════════════════════════════════ */
let currentUtterance = null;
let _cachedVoices = [];

function _loadVoices() {
  const v = window.speechSynthesis?.getVoices() || [];
  if (v.length) _cachedVoices = v;
}
if (typeof window !== "undefined" && window.speechSynthesis) {
  window.speechSynthesis.addEventListener("voiceschanged", _loadVoices);
}

/* Voice preference tables keyed by BCP-47 locale */
const VOICE_PREFS = {
  "hi-IN": [
    v => /swara/i.test(v.name),                                      // Microsoft Swara Neural (Windows 11, best)
    v => /google.*hindi|hindi.*google/i.test(v.name),               // Google Hindi
    v => /google/i.test(v.name) && /^hi/i.test(v.lang),             // Any Google hi-IN
    v => /lekha/i.test(v.name),                                      // Apple Lekha (macOS)
    v => /heera/i.test(v.name),                                      // Microsoft Heera
    v => /ravi/i.test(v.name),                                       // Microsoft Ravi
    v => /kalpana/i.test(v.name),                                    // Microsoft Kalpana
    v => v.lang === "hi-IN",                                         // Any hi-IN voice
    v => v.lang.startsWith("hi"),                                    // Any Hindi
  ],
  "mr-IN": [
    v => /google/i.test(v.name) && /^mr/i.test(v.lang),
    v => v.lang === "mr-IN",
    v => v.lang.startsWith("mr"),
    v => v.lang === "hi-IN",          // fallback to Hindi
  ],
  "ta-IN": [
    v => /google/i.test(v.name) && /^ta/i.test(v.lang),
    v => v.lang === "ta-IN",
    v => v.lang.startsWith("ta"),
  ],
  "te-IN": [
    v => /google/i.test(v.name) && /^te/i.test(v.lang),
    v => v.lang === "te-IN",
    v => v.lang.startsWith("te"),
  ],
  "en-IN": [
    v => /rishi/i.test(v.name),
    v => /veena/i.test(v.name),
    v => /google/i.test(v.name) && v.lang === "en-IN",
    v => v.lang === "en-IN",
  ],
};

function _pickVoice(locale) {
  if (!_cachedVoices.length) _loadVoices();
  const voices = _cachedVoices;
  if (!voices.length) return null;
  // 1. Try preferred voices for the requested locale
  const tests = VOICE_PREFS[locale] || [];
  for (const t of tests) { const f = voices.find(t); if (f) return f; }
  // 2. Try any voice matching the locale language prefix
  const lang2 = locale.split("-")[0].toLowerCase();
  const byLang = voices.find(v => v.lang.toLowerCase().startsWith(lang2));
  if (byLang) return byLang;
  // 3. Try hi-IN preferences if locale was something else
  if (locale !== "hi-IN") {
    for (const t of (VOICE_PREFS["hi-IN"]||[])) { const f = voices.find(t); if (f) return f; }
  }
  // 4. Absolute fallback: any Indian English or first available voice
  const inEn = voices.find(v => v.lang === "en-IN") || voices.find(v => v.lang.startsWith("en")) || voices[0];
  return inEn || null;
}

/* App language → TTS config
   text: "devnagari" | "sanskrit"
   locale: BCP-47 locale string */
const LANG_TTS = {
  "English":  { locale:"en-IN", text:"romanized", requireNative:false },
  "Hindi":    { locale:"hi-IN", text:"devnagari", requireNative:false },  // Changed: always try TTS
  "Sanskrit": { locale:"hi-IN", text:"devnagari", requireNative:false },  // Changed: always try TTS
  "Marathi":  { locale:"mr-IN", text:"devnagari", requireNative:false },  // Changed: always try TTS
  "Tamil":    { locale:"ta-IN", text:"romanized", requireNative:false },  // Changed: always try TTS
  "Telugu":   { locale:"te-IN", text:"romanized", requireNative:false },  // Changed: always try TTS
};

function getMantraDisplayText(m, appLang="English"){
  const cfg = LANG_TTS[appLang] || LANG_TTS.English;
  return cfg.text === "devnagari" ? m.devnagari : m.sanskrit;
}

function getAudioStatusLabel(appLang="English"){
  const cfg = LANG_TTS[appLang] || LANG_TTS.English;
  return cfg.requireNative ? `${appLang} native voice required` : `${appLang} voice`;
}

/* Core speaker — used by all speak functions.
   Handles:
   • Chrome "stuck synthesis" bug → resume() before cancel+speak
   • Async voice loading → waits for voiceschanged if voices not ready
   • 150 ms settle delay after cancel before speaking
   • onerror → always calls onEnd so UI state resets cleanly           */
function _doSpeak({text, locale, rate=0.7, pitch=0.85, onEnd}) {
  if (!window.speechSynthesis) return false;
  const build = () => {
    if (window.speechSynthesis.paused) window.speechSynthesis.resume();
    window.speechSynthesis.cancel();
    setTimeout(() => {
      const utter = new SpeechSynthesisUtterance(text);
      const voice = _pickVoice(locale);
      if (voice) utter.voice = voice;
      utter.lang = locale;
      utter.rate  = rate;
      utter.pitch = pitch;
      utter.volume = 1;
      const done = () => { currentUtterance = null; if (onEnd) onEnd(); };
      utter.onend   = done;
      utter.onerror = done;      // reset UI even on error
      currentUtterance = utter;
      if (window.speechSynthesis.paused) window.speechSynthesis.resume();
      window.speechSynthesis.speak(utter);
    }, 150);
  };
  // Ensure voices are loaded before selecting
  const v = window.speechSynthesis.getVoices();
  if (v.length) { _cachedVoices = v; build(); }
  else {
    window.speechSynthesis.addEventListener("voiceschanged", () => {
      _cachedVoices = window.speechSynthesis.getVoices() || [];
      build();
    }, { once: true });
    setTimeout(build, 600);  // fallback if event never fires
  }
  return true;
}

/* speakMantra — language-aware, slow devotional pace
   Strategy:
   1. Try the locale's preferred Indian voice
   2. If no Indian voice is installed → use romanized text + best available voice
      (romanized Sanskrit is phonetically readable by any TTS engine)
*/
function _hasIndianVoice(locale) {
  const voices = window.speechSynthesis?.getVoices() || _cachedVoices;
  if (!voices.length) return false;
  const lang2 = locale.split("-")[0]; // "hi" from "hi-IN"
  return voices.some(v => v.lang === locale || v.lang.startsWith(lang2+"-IN") || v.lang.startsWith(lang2));
}

/* Best available English voice — prefers Google/premium/neural for clarity */
function _bestEnglishVoice() {
  const voices = _cachedVoices.length ? _cachedVoices : (window.speechSynthesis?.getVoices()||[]);
  const en = voices.filter(v => v.lang.startsWith("en"));
  return (
    en.find(v => /google.*us/i.test(v.name)) ||
    en.find(v => /google/i.test(v.name)) ||
    en.find(v => /premium|enhanced|neural|natural/i.test(v.name)) ||
    en.find(v => v.lang === "en-US") ||
    en.find(v => v.lang === "en-GB") ||
    en[0] || null
  );
}

/* speakMantra — HINDI ONLY.
   Priority chain:
   1. ResponsiveVoice "Hindi Female" (loaded from index.html script tag)
   2. Web Speech API with hi-IN / Indian language voice
   3. AudioEngine Web Speech hi-IN (strict — no English fallback)
   If no Hindi voice is available on the device, onEnd() is called so
   UI state resets, but NO English voice is ever used for mantra audio.
*/
/* ════════════════════════════════════════════════════════════════
   CENTRAL AUDIO ENGINE — speakMantra
   Architecture: Hybrid B+C. Hindi-speaking audio only.
   Tier 1: ResponsiveVoice "Hindi Female" (network TTS, best quality)
   Tier 2: Web Speech API hi-IN voice (device-native, great on Chrome/Safari)
   Tier 3: Web Speech API en-IN / any Indian voice + ROMANIZED text
           (Indian English CAN read roman script — Devanagari cannot be
           pronounced by en-IN, so we swap to transliteration automatically)
   Tier 4: Synchronous fail → returns {ok:false} immediately so callers
           can show a message instead of "Playing..." with silence.

   KEY FIXES vs previous versions:
   • Synchronous voice check: if voices are loaded and none suitable,
     returns {ok:false} BEFORE any async work, so buttons never show
     "Playing..." with no audio
   • en-IN last resort uses ROMANIZED text (not Devanagari — en-IN
     voice cannot pronounce Devanagari characters)
   • Safety timeout reduced to 6s
   • All async paths still call onEnd() on failure (UI always resets)
   ════════════════════════════════════════════════════════════════ */
let currentAudio = null;

function stopActiveAudioPlayback(){
  try { if (currentAudio) { currentAudio.pause(); currentAudio.currentTime = 0; currentAudio.src = ""; } } catch(e) {}
  currentAudio = null;
  try { if (window.responsiveVoice && typeof window.responsiveVoice.cancel === "function") window.responsiveVoice.cancel(); } catch(e) {}
  try { if (window.speechSynthesis) window.speechSynthesis.cancel(); } catch(e) {}
  currentUtterance = null;
}

function buildHindiTtsUrls(text){
  const q = encodeURIComponent((text||"").trim().slice(0, 220));
  if (!q) return [];
  return [
    `https://translate.google.com/translate_tts?ie=UTF-8&client=tw-ob&tl=hi&q=${q}`,
    `https://translate.googleapis.com/translate_tts?ie=UTF-8&client=gtx&tl=hi&q=${q}`
  ];
}

function playRemoteHindiAudio(text, onEnd){
  // Disabled on purpose. Remote TTS URLs were causing audio to start and stop
  // immediately on some browsers due to throttling/CORS/rate-limit behavior.
  // Keep this helper returning false so the app always uses the stable local
  // speech engine below.
  return false;
}

function _pickUsableVoice(voices){
  const list = Array.isArray(voices) ? voices : [];
  return (
    list.find(v => /^hi(-|$)/i.test(v.lang||"")) ||
    list.find(v => /hindi/i.test(v.name||"")) ||
    list.find(v => /^mr(-|$)/i.test(v.lang||"")) ||
    list.find(v => /^sa(-|$)/i.test(v.lang||"")) ||
    list.find(v => /^en-IN$/i.test(v.lang||"")) ||
    list.find(v => /india|indian/i.test(`${v.name||""} ${v.lang||""}`)) ||
    list.find(v => /^en(-|$)/i.test(v.lang||"")) ||
    list[0] || null
  );
}

function speakMantra(devnagari, romanized, onEnd, appLang="English") {
  if (typeof window === "undefined") { onEnd?.(); return { ok: false, reason: "ssr" }; }

  const textDev = (devnagari || "").trim().slice(0, 500);
  const textRom = (romanized || devnagari || "").trim().slice(0, 500);
  const playableText = textDev || textRom;
  if (!playableText) { onEnd?.(); return { ok: false, reason: "no-text" }; }

  stopActiveAudioPlayback();

  // Best-quality path when the external library is present.
  try {
    if (window.responsiveVoice && typeof window.responsiveVoice.speak === "function") {
      const textToSpeak = textDev || textRom;
      currentUtterance = { type: "responsiveVoice" };
      let finished = false;
      let started = false;
      const finish = () => {
        if (finished) return;
        finished = true;
        currentUtterance = null;
        onEnd?.();
      };
      window.responsiveVoice.cancel?.();
      window.responsiveVoice.speak(textToSpeak, "Hindi Female", {
        rate: 0.84,
        pitch: 1,
        volume: 1,
        onstart: () => { started = true; },
        onend: finish,
        onerror: () => {
          // fall through to local speech engine below only if it never started
          if (!started) finish();
        },
      });
      // Do not auto-finish aggressively; give the engine time to actually start.
      setTimeout(() => {
        try {
          if (window.responsiveVoice?.isPlaying?.()) return;
        } catch (e) {}
        if (!started) {
          currentUtterance = null;
          // continue below to Web Speech fallback
        }
      }, 1800);
      if (started || window.responsiveVoice?.isPlaying?.()) {
        return { ok: true, engine: "responsivevoice-hi" };
      }
    }
  } catch (e) {
    // fall through
  }

  if (!window.speechSynthesis || typeof SpeechSynthesisUtterance === "undefined") {
    onEnd?.();
    return { ok: false, reason: "unsupported" };
  }

  const voices = window.speechSynthesis.getVoices ? window.speechSynthesis.getVoices() : [];
  const voice = _pickUsableVoice(voices);
  const prefersNative = !!(voice && (
    /^hi(-|$)/i.test(voice.lang||"") ||
    /^mr(-|$)/i.test(voice.lang||"") ||
    /^sa(-|$)/i.test(voice.lang||"") ||
    /hindi/i.test(voice.name||"")
  ));
  const textToSpeak = prefersNative ? (textDev || textRom) : (textRom || textDev);
  const utter = new SpeechSynthesisUtterance(textToSpeak);
  if (voice) utter.voice = voice;
  utter.lang = voice?.lang || (prefersNative ? "hi-IN" : "en-IN");
  utter.rate = 0.82;
  utter.pitch = 1.0;
  utter.volume = 1;
  currentUtterance = utter;

  let finished = false;
  let started = false;
  const finish = () => {
    if (finished) return;
    finished = true;
    currentUtterance = null;
    onEnd?.();
  };
  utter.onstart = () => { started = true; };
  utter.onend = finish;
  utter.onerror = finish;

  try {
    window.speechSynthesis.cancel();
    if (window.speechSynthesis.paused) window.speechSynthesis.resume();
    setTimeout(() => {
      try {
        window.speechSynthesis.speak(utter);
        setTimeout(() => {
          if (started || window.speechSynthesis.speaking || window.speechSynthesis.pending) return;
          finish();
        }, 1800);
      } catch (e) {
        finish();
      }
    }, 80);
    return { ok: true, engine: voice ? "webspeech-voice" : "webspeech-default" };
  } catch (e) {
    finish();
    return { ok: false, reason: "speak-failed" };
  }
}

/* speakStep — ritual step guidance audio (same engine as speakMantra).
   Step text is English/romanized — pass as BOTH args so the shared audio
   pipeline can still speak it using the remote Hindi audio / Indian voice path. */
function speakStep(text, onEnd) {
  return speakMantra(text, text, onEnd, "Hindi");
}

/* Legacy alias */
function speakText(text, onEnd) { return speakMantra(text, text, onEnd, "English"); }

function stopSpeech() {
  stopActiveAudioPlayback();
}

