function getMoonPhase(date){
  const synodicMonth=29.530588853;
  const reference=new Date("2000-01-06T18:14:00Z");
  const days=(date-reference)/(1000*60*60*24);
  const phase=((days%synodicMonth)+synodicMonth)%synodicMonth;
  if(phase<1||phase>28.5)return{name:"Amavasya",emoji:"🌑",pct:0,significance:"New Moon — most powerful for Pitru puja, Shiva meditation and new resolutions. Avoid auspicious ceremonies.",color:"#1E293B"};
  if(phase<3.7)return{name:"Pratipada",emoji:"🌒",pct:8,significance:"Shukla Pratipada — fresh beginning of the lunar fortnight. Excellent for new ventures.",color:"#475569"};
  if(phase<7.4)return{name:"Panchami–Saptami",emoji:"🌓",pct:35,significance:"First quarter — growing energy for undertaking work, studies and projects.",color:"#64748B"};
  if(phase<11.1)return{name:"Dashami–Ekadashi",emoji:"🌔",pct:70,significance:"Ekadashi is highly auspicious — fast on this day for Vishnu's blessings and spiritual merit.",color:"#94A3B8"};
  if(phase<15.7)return{name:"Purnima",emoji:"🌕",pct:100,significance:"Full Moon — the holiest day of the lunar month. Ideal for Satyanarayan Katha, Lakshmi puja and ancestral offerings.",color:"#FCD34D"};
  if(phase<18.4)return{name:"Shodashi–Ashtami (K)",emoji:"🌖",pct:75,significance:"Krishna paksha begins — good for inner work, meditation and healing rituals.",color:"#94A3B8"};
  if(phase<22.1)return{name:"Krishna Ekadashi",emoji:"🌗",pct:45,significance:"Krishna Paksha Ekadashi — equally potent for Vishnu fast as Shukla Ekadashi.",color:"#64748B"};
  if(phase<25.8)return{name:"Trayodashi–Chaturdashi",emoji:"🌘",pct:15,significance:"Pradosh Kaal approaching — Pradosh fast on Trayodashi is auspicious for Shiva.",color:"#475569"};
  return{name:"Chaturdashi",emoji:"🌑",pct:5,significance:"Masik Shivaratri — fast and worship Shiva on every Chaturdashi of Krishna Paksha.",color:"#1E293B"};
}

/* ── Festival Alert Banner ── */
function FestivalAlertBanner({S}){
  const today=new Date();
  const todayM=today.getMonth(),todayD=today.getDate();
  const tomorrow=new Date(today);tomorrow.setDate(today.getDate()+1);
  const tomM=tomorrow.getMonth(),tomD=tomorrow.getDate();
  // Collect today + tomorrow festivals — always visible, no dismiss
  const alerts=FESTIVALS.filter(f=>{
    const isToday=f.month===todayM&&f.day===todayD;
    const isTomorrow=f.month===tomM&&f.day===tomD;
    return isToday||isTomorrow;
  }).slice(0,3);
  if(!alerts.length)return null;
  return(
    <div style={{marginBottom:12}}>
      {alerts.map(f=>{
        const isToday=f.month===todayM&&f.day===todayD;
        return(
          <div key={f.id} style={{display:"flex",alignItems:"center",gap:12,background:"linear-gradient(90deg,"+f.color+"28,"+f.color+"12)",border:"1px solid "+f.color+"66",borderRadius:14,padding:"12px 16px",marginBottom:6,boxShadow:"0 2px 12px "+f.color+"22"}}>
            <div style={{width:40,height:40,borderRadius:12,background:f.color+"33",display:"flex",alignItems:"center",justifyContent:"center",fontSize:22,flexShrink:0}}>{f.icon}</div>
            <div style={{flex:1,minWidth:0}}>
              <p style={{color:f.color,fontSize:12,fontWeight:900,margin:"0 0 2px",letterSpacing:"0.05em",textTransform:"uppercase"}}>
                {isToday?"🎉 Today":"⏰ Tomorrow"} — {f.name}
              </p>
              <p style={{color:S.muted,fontSize:11,margin:0,lineHeight:1.5}}>{isToday?"Auspicious day — perform puja, fasting or special prayers":"Sacred festival tomorrow — prepare offerings and prayers"}</p>
            </div>
            <span style={{background:f.color+"22",color:f.color,fontSize:11,fontWeight:800,padding:"4px 10px",borderRadius:10,flexShrink:0,border:"1px solid "+f.color+"44"}}>{isToday?"TODAY":"TOMORROW"}</span>
          </div>
        );
      })}
    </div>
  );
}

function CityPickerWidget({S,selectedLocation,setSelectedLocation,showAllCities,setShowAllCities}){
  const CITY_PAGE=18;
  const visible=showAllCities?LOCATION_OPTIONS:LOCATION_OPTIONS.slice(0,CITY_PAGE);
  return(
    <div style={{marginTop:10,paddingTop:10,borderTop:"1px solid "+S.border}}>
      <div style={{color:S.muted,fontSize:12,fontWeight:700,marginBottom:7}}>📍 Panchang location</div>
      <div style={{display:"flex",gap:6,flexWrap:"wrap"}}>
        {visible.map(loc=>(
          <button key={loc.key} onClick={()=>setSelectedLocation(loc.key)}
            style={{padding:"5px 10px",borderRadius:16,border:selectedLocation===loc.key?"none":"1px solid "+S.border,
              background:selectedLocation===loc.key?S.saffron:"transparent",color:selectedLocation===loc.key?"#FFFFFF":S.muted,
              fontSize:12,fontWeight:selectedLocation===loc.key?700:500,cursor:"pointer"}}>
            {loc.label}
          </button>
        ))}
      </div>
      {!showAllCities&&LOCATION_OPTIONS.length>CITY_PAGE&&(
        <button onClick={()=>setShowAllCities(true)}
          style={{marginTop:8,padding:"4px 12px",borderRadius:12,border:"1px solid "+S.border,background:"transparent",color:S.gold,fontSize:11,fontWeight:700,cursor:"pointer"}}>
          ＋ View all {LOCATION_OPTIONS.length} cities
        </button>
      )}
      {showAllCities&&(
        <button onClick={()=>setShowAllCities(false)}
          style={{marginTop:8,padding:"4px 12px",borderRadius:12,border:"1px solid "+S.border,background:"transparent",color:S.muted,fontSize:11,fontWeight:600,cursor:"pointer"}}>
          ↑ Show fewer
        </button>
      )}
    </div>
  );
}

