function MantraLibraryPanel({S,bp,isPremium,onPremium}){
  const[search,setSearch]=useState("");
  const[catFilter,setCatFilter]=useState("All");
  const[selected,setSelected]=useState(null);
  const[ttsNotice,setTtsNotice]=useState("");
  // No local libVid — video opens via global openVideo() modal
  const MANTRA_PAGE=5;
  const[showAllMantras,setShowAllMantras]=useState(false);

  const cats=["All","Universal","Shiva","Vishnu","Devi","Ganesha","Hanuman"];
  const filtered=MANTRA_LIBRARY.filter(m=>{
    const matchCat=catFilter==="All"||m.cat===catFilter;
    const q=search.toLowerCase();
    const matchSearch=!q||m.name.toLowerCase().includes(q)||m.deity.toLowerCase().includes(q)||m.purpose.toLowerCase().includes(q);
    return matchCat&&matchSearch;
  }).sort((a,b)=>a.name.localeCompare(b.name));
  const visible=showAllMantras?filtered:filtered.slice(0,MANTRA_PAGE);

  if(selected){
    return(
      <div>
        <button onClick={()=>{ setSelected(null); }}
          style={{display:"flex",alignItems:"center",gap:6,background:"transparent",border:"none",color:S.muted,fontSize:12,cursor:"pointer",marginBottom:14,padding:0}}>
          ← Back to Library
        </button>
        <div style={{background:"linear-gradient(135deg,"+selected.color+"22,"+selected.color+"08)",borderRadius:18,padding:"16px",marginBottom:12,border:"1px solid "+selected.color+"55"}}>
          <div style={{display:"flex",alignItems:"center",gap:12,marginBottom:12}}>
            <div style={{width:52,height:52,borderRadius:14,background:selected.color+"33",display:"flex",alignItems:"center",justifyContent:"center",fontSize:26,flexShrink:0}}>{selected.icon}</div>
            <div>
              <h2 style={{color:"#FFFFFF",fontSize:16,fontWeight:900,margin:"0 0 2px"}}>{selected.name}</h2>
              <p style={{color:selected.color,fontSize:11,fontWeight:700,margin:"0 0 2px"}}>{selected.deity}</p>
              <p style={{color:S.muted,fontSize:11,margin:0}}>⏰ {selected.bestTime} · 📿 {selected.chants}x</p>
            </div>
          </div>
          <div style={{background:"rgba(0,0,0,0.3)",borderRadius:12,padding:"12px 14px",marginBottom:10}}>
            <p style={{color:S.gold,fontSize:11,fontWeight:800,margin:"0 0 6px",textTransform:"uppercase",letterSpacing:1}}>Sanskrit</p>
            <p style={{color:"#FFFFFF",fontSize:13,fontWeight:700,margin:0,lineHeight:1.7,fontFamily:"serif"}}>{selected.sanskrit}</p>
          </div>
          <div style={{background:"rgba(0,0,0,0.2)",borderRadius:12,padding:"12px 14px",marginBottom:10}}>
            <p style={{color:S.gold,fontSize:11,fontWeight:800,margin:"0 0 6px",textTransform:"uppercase",letterSpacing:1}}>Transliteration</p>
            <p style={{color:"rgba(255,255,255,0.8)",fontSize:12,margin:0,lineHeight:1.7,fontStyle:"italic"}}>{selected.transliteration}</p>
          </div>
          <div style={{background:"rgba(0,0,0,0.2)",borderRadius:12,padding:"12px 14px",marginBottom:10}}>
            <p style={{color:S.gold,fontSize:11,fontWeight:800,margin:"0 0 6px",textTransform:"uppercase",letterSpacing:1}}>Meaning</p>
            <p style={{color:"rgba(255,255,255,0.75)",fontSize:12,margin:0,lineHeight:1.6}}>{selected.meaning}</p>
          </div>
          <div style={{background:"rgba(0,0,0,0.2)",borderRadius:12,padding:"12px 14px"}}>
            <p style={{color:S.gold,fontSize:11,fontWeight:800,margin:"0 0 6px",textTransform:"uppercase",letterSpacing:1}}>✨ Benefits</p>
            <p style={{color:"rgba(255,255,255,0.75)",fontSize:12,margin:0,lineHeight:1.6}}>{selected.benefits}</p>
          </div>
          {/* Listen / TTS + Video action row */}
          <div style={{marginTop:8}}>
            <div style={{display:"flex",gap:8,flexWrap:"wrap"}}>
              <button onClick={()=>{
                  const r=speakMantra(selected.sanskrit, selected.transliteration, null, "Hindi");
                  if(r?.ok===false) setTtsNotice("Hindi voice not available on this device. Try Chrome on Android or install a Hindi language pack.");
                }}
                style={{padding:"8px 16px",borderRadius:10,border:"1px solid #9C27B055",background:"linear-gradient(135deg,#9C27B033,#7B5EA722)",color:"#CE93D8",fontSize:12,fontWeight:700,cursor:"pointer"}}>
                🔊 Chant in Hindi Voice
              </button>
              <button onClick={()=>openVideo(selected.ytIds||[], (selected.name||"")+" mantra full 108 times", selected.name)}
                style={{padding:"7px 14px",borderRadius:10,border:"1px solid rgba(255,0,0,0.3)",background:"rgba(255,0,0,0.1)",color:"#FF8080",fontSize:12,fontWeight:700,cursor:"pointer",display:"flex",alignItems:"center",gap:5}}>
                ▶ Watch in App
              </button>
            </div>
          </div>
        </div>
        <div style={{background:S.card,borderRadius:14,padding:"12px 14px",border:"1px solid "+S.border}}>
          <p style={{color:S.gold,fontSize:11,fontWeight:800,margin:"0 0 6px",textTransform:"uppercase",letterSpacing:1}}>🎯 Purpose</p>
          <p style={{color:S.text,fontSize:13,fontWeight:700,margin:0}}>{selected.purpose}</p>
        </div>
      </div>
    );
  }

  return(
    <div>
      {ttsNotice&&(
        <div style={{background:"rgba(255,180,50,0.15)",border:"1px solid rgba(255,180,50,0.4)",borderRadius:10,padding:"10px 14px",marginBottom:10,display:"flex",alignItems:"flex-start",gap:8}}>
          <span style={{fontSize:16}}>ℹ️</span>
          <p style={{color:"#FFB84D",fontSize:12,margin:0,lineHeight:1.5,flex:1}}>{ttsNotice}</p>
          <button onClick={()=>setTtsNotice("")} style={{background:"transparent",border:"none",color:"#FFB84D",fontSize:16,cursor:"pointer",padding:0,lineHeight:1}}>✕</button>
        </div>
      )}
      <div style={{background:"linear-gradient(135deg,#1A0828,#280A10)",borderRadius:18,padding:"14px 16px",marginBottom:14,border:"1px solid "+S.saffron+"44",display:"flex",alignItems:"center",gap:12}}>
        <div style={{width:44,height:44,borderRadius:14,background:S.saffron+"30",display:"flex",alignItems:"center",justifyContent:"center",fontSize:22,flexShrink:0}}>📿</div>
        <div>
          <h2 style={{color:"#FFFFFF",fontSize:15,fontWeight:900,margin:0}}>Mantra Library</h2>
          <p style={{color:"rgba(255,255,255,0.55)",fontSize:12,margin:"2px 0 0"}}>{MANTRA_LIBRARY.length} sacred mantras · Sanskrit · Meaning · Benefits</p>
        </div>
      </div>

      {/* Search */}
      <div style={{position:"relative",marginBottom:10}}>
        <span style={{position:"absolute",left:12,top:"50%",transform:"translateY(-50%)",color:S.muted,fontSize:14}}>🔍</span>
        <input value={search} onChange={e=>setSearch(e.target.value)} placeholder="Search by name, deity, or purpose..."
          style={{width:"100%",boxSizing:"border-box",padding:"10px 12px 10px 34px",borderRadius:12,border:"1px solid "+S.border,background:S.card,color:S.text,fontSize:12,outline:"none"}}/>
      </div>

      {/* Category filter */}
      <div style={{display:"flex",gap:5,flexWrap:"wrap",marginBottom:14}}>
        {cats.map(c=>(
          <button key={c} onClick={()=>setCatFilter(c)}
            style={{padding:"4px 10px",borderRadius:20,border:"1px solid "+(catFilter===c?S.saffron:S.border),background:catFilter===c?"linear-gradient(135deg,"+S.saffron+","+S.gold+")":"transparent",color:catFilter===c?"#fff":S.muted,fontSize:11,fontWeight:catFilter===c?800:600,cursor:"pointer"}}>
            {c}
          </button>
        ))}
      </div>

      {/* Mantra list */}
      {visible.map(m=>(
        <div key={m.id} onClick={()=>setSelected(m)}
          style={{background:S.card,borderRadius:14,padding:"12px 14px",marginBottom:8,border:"1px solid "+S.border,display:"flex",gap:12,alignItems:"center",cursor:"pointer",transition:"border 0.2s"}}
          onMouseEnter={e=>e.currentTarget.style.borderColor=m.color+"88"}
          onMouseLeave={e=>e.currentTarget.style.borderColor=S.border}>
          <div style={{width:40,height:40,borderRadius:12,background:m.color+"22",border:"1px solid "+m.color+"44",display:"flex",alignItems:"center",justifyContent:"center",fontSize:18,flexShrink:0}}>{m.icon}</div>
          <div style={{flex:1,minWidth:0}}>
            <p style={{color:S.text,fontSize:13,fontWeight:800,margin:"0 0 2px",whiteSpace:"nowrap",overflow:"hidden",textOverflow:"ellipsis"}}>{m.name}</p>
            <p style={{color:m.color,fontSize:11,fontWeight:700,margin:"0 0 2px"}}>{m.deity}</p>
            <p style={{color:S.muted,fontSize:11,margin:"0 0 3px"}}>{m.purpose}</p>
            <p style={{color:S.gold,fontSize:11,margin:0,fontWeight:600}}>📖 Tap to read Sanskrit text &amp; meaning →</p>
          </div>
          <span style={{color:S.muted,fontSize:16,flexShrink:0}}>›</span>
        </div>
      ))}
      {filtered.length>MANTRA_PAGE&&(
        <button onClick={()=>setShowAllMantras(v=>!v)}
          style={{width:"100%",marginTop:8,padding:"8px",borderRadius:12,border:"1px solid "+S.border,background:"transparent",color:S.gold,fontSize:12,fontWeight:700,cursor:"pointer"}}>
          {showAllMantras?`↑ Show fewer`:`＋ View all ${filtered.length} mantras`}
        </button>
      )}
      {filtered.length===0&&<p style={{color:S.muted,fontSize:12,textAlign:"center",padding:"20px 0"}}>No mantras found for "{search}"</p>}
    </div>
  );
}

