const SANKALP_MONTHS_HINDI=["चैत्र","वैशाख","ज्येष्ठ","आषाढ","श्रावण","भाद्रपद","आश्विन","कार्तिक","मार्गशीर्ष","पौष","माघ","फाल्गुन"];
const SANKALP_WEEKDAYS=["रविवार","सोमवार","मंगलवार","बुधवार","गुरुवार","शुक्रवार","शनिवार"];
const SANKALP_PUJAS=[
  "Ganesh Puja","Lakshmi Puja","Satyanarayan Katha","Rudrabhishek","Griha Pravesh","Navagraha Puja","Vastu Shanti","Sunderkand Path","Hanuman Chalisa Path","Kali Puja","Durga Puja","Saraswati Puja","Vishnu Puja","Shiva Puja","Pitru Tarpan","Birthday Puja","Wedding Puja","Thread Ceremony (Upanayana)","Annaprashan","Namkaran"
];

function SankalpGeneratorPanel({S,bp}){
  const[name,setName]=useState("");
  const[copied,setCopied]=useState(false);
  const[gotra,setGotra]=useState("");
  const[city,setCity]=useState("");
  const[puja,setPuja]=useState(SANKALP_PUJAS[0]);
  const[result,setResult]=useState(null);
  const now=new Date();
  const weekday=SANKALP_WEEKDAYS[now.getDay()];
  const hindiMonth=SANKALP_MONTHS_HINDI[now.getMonth()];
  const samvatYear=now.getFullYear()-57;
  const generate=()=>{
    if(!name.trim()||!gotra.trim()||!city.trim()){alert("Please enter your name, gotra, and city.");return;}
    const sankalp=`ॐ विष्णुर्विष्णुर्विष्णुः। श्रीमद्भगवतो महापुरुषस्य विष्णोराज्ञया प्रवर्तमानस्य अद्य ब्रह्मणो द्वितीये परार्धे श्री श्वेत वाराहकल्पे वैवस्वतमन्वन्तरे अष्टाविंशतितमे कलियुगे, कलिप्रथमचरणे, जम्बूद्वीपे, भारतवर्षे, भरतखण्डे, ${city} क्षेत्रे, ${weekday}, ${hindiMonth} मासे, विक्रमसंवत् ${samvatYear} वर्षे — अस्मिन् शुभतिथौ, श्री ${name}, ${gotra} गोत्रोत्पन्नः, अपने समस्त परिवार की कुशलता एवं शुभकामना हेतु, श्री ${puja} कर्म करिष्यते। संकल्पितोऽस्मि।`;
    setResult(sankalp);
  };
  return(
    <div style={{display:"flex",flexDirection:"column",gap:12}}>
      <div style={{background:"linear-gradient(135deg,rgba(255,192,64,0.10),rgba(255,120,50,0.08))",borderRadius:16,padding:"14px 16px",border:"1px solid rgba(255,192,64,0.3)"}}>
        <div style={{display:"flex",alignItems:"center",gap:10}}>
          <span style={{fontSize:24}}>📜</span>
          <div>
            <h3 style={{color:S.text,fontSize:15,fontWeight:900,margin:0}}>Sankalp Generator</h3>
            <p style={{color:S.muted,fontSize:11,margin:"2px 0 0"}}>Generate your personal Sanskrit sankalp (पूजा संकल्प) for any puja</p>
          </div>
        </div>
      </div>
      <div style={{background:S.card,borderRadius:14,padding:"14px 16px",border:"1px solid "+S.border,display:"flex",flexDirection:"column",gap:10}}>
        {[["Your Full Name (Sanskrit/Hindi)","e.g. Ram Kumar Sharma",name,setName],["Gotra (Family Lineage)","e.g. Kashyap, Bharadwaj, Atreya",gotra,setGotra],["City / Location","e.g. Delhi, Mumbai, Austin",city,setCity]].map(([lbl,ph,val,setter])=>(
          <div key={lbl}>
            <p style={{color:S.muted,fontSize:11,fontWeight:700,margin:"0 0 4px",textTransform:"uppercase",letterSpacing:0.7}}>{lbl}</p>
            <input value={val} onChange={e=>setter(e.target.value)} placeholder={ph}
              style={{width:"100%",boxSizing:"border-box",padding:"9px 12px",borderRadius:10,border:"1px solid "+S.border,background:S.bg,color:S.text,fontSize:13,outline:"none"}}/>
          </div>
        ))}
        <div>
          <p style={{color:S.muted,fontSize:11,fontWeight:700,margin:"0 0 4px",textTransform:"uppercase",letterSpacing:0.7}}>Puja / Occasion</p>
          <select value={puja} onChange={e=>setPuja(e.target.value)}
            style={{width:"100%",padding:"9px 12px",borderRadius:10,border:"1px solid "+S.border,background:S.bg,color:S.text,fontSize:13,outline:"none"}}>
            {SANKALP_PUJAS.map(p=><option key={p} value={p}>{p}</option>)}
          </select>
        </div>
        <button onClick={generate}
          style={{width:"100%",padding:"12px",borderRadius:12,border:"none",background:"linear-gradient(90deg,"+S.saffron+","+S.gold+")",color:"#fff",fontSize:14,fontWeight:800,cursor:"pointer",marginTop:4}}>
          📜 Generate Sankalp
        </button>
      </div>
      {result&&(
        <div style={{background:"linear-gradient(135deg,rgba(255,192,64,0.08),rgba(255,120,50,0.05))",borderRadius:14,padding:"16px",border:"1px solid rgba(255,192,64,0.4)"}}>
          <p style={{color:S.gold,fontSize:12,fontWeight:800,margin:"0 0 10px",textTransform:"uppercase",letterSpacing:1}}>📜 Your Sankalp</p>
          <p style={{color:S.text,fontSize:14,fontFamily:"'Noto Sans Devanagari',serif",lineHeight:1.8,margin:"0 0 12px"}}>{result}</p>
          <button onClick={()=>navigator.clipboard?.writeText(result).then(()=>{setCopied(true);setTimeout(()=>setCopied(false),2000);})}
            style={{padding:"7px 16px",borderRadius:10,border:"1px solid "+S.border,background:"transparent",color:S.gold,fontSize:12,fontWeight:700,cursor:"pointer",marginRight:8}}>
            📋 Copy Sankalp
          </button>
          <button onClick={()=>{const txt="📜 *My Puja Sankalp*\n\n"+result+"\n\n_Generated via Vedanta Calendar AI_";openSharePanel("My Puja Sankalp",txt);}}
            style={{padding:"7px 16px",borderRadius:10,border:"none",background:"#25D366",color:"#fff",fontSize:12,fontWeight:700,cursor:"pointer"}}>
            📤 Share
          </button>
        </div>
      )}
      <div style={{background:S.card,borderRadius:12,padding:"11px 14px",border:"1px solid "+S.border}}>
        <p style={{color:S.muted,fontSize:11,margin:0,lineHeight:1.6}}>📜 <strong style={{color:S.text}}>What is a Sankalp?</strong> A sankalp is a formal declaration of intent made before any puja. It establishes the time, place, person, and purpose — connecting you to the cosmic order before you begin worship. Read by the pandit or by yourself before starting.</p>
      </div>
    </div>
  );
}

